const expectedToken = 'REPLACE_WITH_RABBIT_TOKEN';

function parsePayload(input) {
  const direct = input.payload ?? input.body?.payload ?? input.body ?? input;

  if (typeof direct === 'string') {
    try {
      return JSON.parse(direct);
    } catch (error) {
      return { message: direct };
    }
  }

  return direct || {};
}

const payload = parsePayload($json);
const token = String(payload.token || payload.apiKey || payload.key || '');
const tokenConfigured = expectedToken && !expectedToken.startsWith('REPLACE_WITH_');
const valid = Boolean(tokenConfigured && token === expectedToken);
const message = String(payload.message || payload.text || payload.transcript || '').trim();
const audioBase64 = String(payload.audioBase64 || payload.audio || '').trim();
const imageBase64 = String(payload.imageBase64 || payload.image || payload.photoBase64 || '').trim();
const now = new Date().toISOString();

return [{
  json: {
    valid,
    revoked: !valid,
    status: valid ? 'ok' : 'revoked',
    reply: valid ? 'Procesando Mind Drop.' : 'Token revocado o invalido.',
    message,
    inputMode: String(payload.inputMode || (audioBase64 ? 'audio' : imageBase64 ? 'image' : 'text')),
    audioBase64,
    audioMimeType: String(payload.audioMimeType || 'audio/webm'),
    audioName: String(payload.audioName || 'rabbit-r1.webm'),
    imageBase64,
    imageMimeType: String(payload.imageMimeType || 'image/jpeg'),
    imageName: String(payload.imageName || 'rabbit-r1-photo.jpg'),
    lang: String(payload.lang || payload.language || 'es-ES'),
    sessionId: String(payload.sessionId || ''),
    source: String(payload.source || 'rabbit-r1-creation'),
    sentAt: payload.sentAt || now,
    receivedAt: now
  }
}];

const openAiApiKey = 'REPLACE_WITH_OPENAI_API_KEY';
const allowedAreas = ['Salud', 'Trabajo', 'Finanzas', 'Relaciones', 'Casa', 'Aprendizaje', 'Ideas', 'Personal', 'Foto'];
const message = String($json.message || '').trim();
const imageBase64 = String($json.imageBase64 || '').replace(/^data:.*?;base64,/, '').trim();
const imageMimeType = String($json.imageMimeType || 'image/jpeg').split(';')[0].trim() || 'image/jpeg';

function withoutMedia(input) {
  const { audioBase64, imageBase64, ...rest } = input;
  return rest;
}

function cleanArea(value) {
  const normalized = String(value || '').trim();
  return allowedAreas.includes(normalized) ? normalized : 'Personal';
}

function fallback(reason = '') {
  const title = message ? message.slice(0, 80) : imageBase64 ? 'Foto Mind Drop' : 'Mind Drop';
  const transcriptionNote = $json.transcriptionError ? `Error de transcripcion: ${$json.transcriptionError}` : '';
  return [{
    json: {
      ...withoutMedia($json),
      titulo: title,
      area: imageBase64 ? 'Foto' : 'Personal',
      observaciones: message || transcriptionNote || (imageBase64 ? 'Foto recibida sin analisis.' : 'Sin mensaje recibido.'),
      aiModel: 'fallback',
      aiFallbackReason: reason || $json.transcriptionError || ''
    }
  }];
}

if (!message && !imageBase64) return fallback('empty_message');
if (!openAiApiKey || openAiApiKey.startsWith('REPLACE_WITH_')) return fallback('missing_openai_key');

const system = [
  'Eres un clasificador de capturas personales llamado Mind Drop.',
  'Recibes una nota breve o una foto en espanol y devuelves solo JSON valido.',
  'Campos obligatorios: titulo, area, observaciones.',
  `area debe ser exactamente una de: ${allowedAreas.join(', ')}.`,
  'Si hay foto, usa siempre el area Foto.',
  'titulo: maximo 80 caracteres, claro y util como titulo de pagina.',
  'observaciones: si hay texto, reescribelo de forma clara y accionable en 1-3 frases. Si hay foto, describe lo importante y por que podria guardarse.',
  'Si hay duda entre areas, usa Personal. Si es una idea suelta, usa Ideas.'
].join(' ');

const userContent = imageBase64
  ? [
      { type: 'text', text: message || 'Analiza esta foto para guardarla como Mind Drop. Devuelve titulo, area y observaciones.' },
      { type: 'image_url', image_url: { url: `data:${imageMimeType};base64,${imageBase64}` } }
    ]
  : message;

try {
  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${openAiApiKey}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: imageBase64 ? 'gpt-4.1-mini' : 'gpt-4.1-nano',
      temperature: 0.1,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userContent }
      ]
    },
    json: true
  });

  const content = data.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(content);
  const titulo = String(parsed.titulo || parsed.title || message).trim().slice(0, 80) || 'Mind Drop';
  const area = imageBase64 ? 'Foto' : cleanArea(parsed.area);
  const observaciones = String(parsed.observaciones || parsed.notes || parsed.observation || message).trim();

  return [{
    json: {
      ...withoutMedia($json),
      titulo,
      area,
      observaciones,
      aiModel: imageBase64 ? 'gpt-4.1-mini' : 'gpt-4.1-nano'
    }
  }];
} catch (error) {
  return fallback(error.message || 'openai_error');
}

const failed = Boolean($json.transcriptionError);
let created = {};
let classified = {};
let tokenPayload = {};
try { created = $('Create Mind Drop row').first().json || {}; } catch (error) {}
try { classified = $('AI classify drop').first().json || {}; } catch (error) {}
try { tokenPayload = $('Validate Rabbit token').first().json || {}; } catch (error) {}

const title = created.Titulo || created.titulo || classified.titulo || $json.Titulo || $json.titulo || 'nuevo drop';
const transcript = String(classified.transcript || classified.message || $json.transcript || $json.message || '').trim();
const notionPageId = created.id || $json.notionPageId || $json.id || '';
const hasInputPhoto = Boolean(tokenPayload.imageBase64);
const photoError = String($json.error?.message || $json.photoUploadError || '').trim();
const photoSaved = Boolean(hasInputPhoto && !photoError && notionPageId);

return [{
  json: {
    ok: !failed,
    status: failed ? 'transcription_error' : 'ok',
    reply: failed
      ? `No pude transcribir el audio: ${$json.transcriptionError}`
      : `Guardado en Mind Drop: ${title}${photoSaved ? ' con foto.' : '.'}`,
    transcript,
    notionPageId,
    area: created.Area || created.area || classified.area || $json.Area || $json.area || '',
    photoSaved,
    photoError
  }
}];

return [{
  json: {
    ok: false,
    revoked: true,
    status: 'revoked',
    reply: 'Token revocado o invalido.'
  }
}];

function withoutAudio(input) {
  const { audioBase64, ...rest } = input;
  return rest;
}

function extensionFor(mimeType) {
  const clean = String(mimeType || '').split(';')[0].trim().toLowerCase();
  if (clean.includes('mp4') || clean.includes('m4a')) return 'm4a';
  if (clean.includes('ogg')) return 'ogg';
  if (clean.includes('wav')) return 'wav';
  if (clean.includes('mpeg') || clean.includes('mp3')) return 'mp3';
  return 'webm';
}

const base64 = String($json.audioBase64 || '').replace(/^data:.*?;base64,/, '');
const rawMimeType = String($json.audioMimeType || 'audio/webm');
const mimeType = rawMimeType.split(';')[0].trim() || 'audio/webm';
const extension = extensionFor(mimeType);
const fileName = String($json.audioName || `rabbit-r1.${extension}`).replace(/[^a-z0-9._-]/gi, '_');
const safeName = fileName.includes('.') ? fileName : `rabbit-r1.${extension}`;

if (!base64) {
  return [{
    json: {
      ...withoutAudio($json),
      message: '',
      transcript: '',
      transcriptionError: 'empty_audio',
      transcriptionModel: 'whisper-1'
    }
  }];
}

return [{
  json: {
    ...withoutAudio($json),
    message: '',
    transcript: '',
    transcriptionModel: 'whisper-1'
  },
  binary: {
    audio: {
      data: base64,
      mimeType,
      fileName: safeName,
      fileExtension: extension
    }
  }
}];

const transcript = String($json.text || $json.transcript || '').trim();
const errorMessage = $json.error?.message || $json.message || '';

if (!transcript) {
  return [{
    json: {
      ...$json,
      message: '',
      transcript: '',
      transcriptionError: errorMessage || 'empty_transcript',
      transcriptionModel: 'whisper-1'
    }
  }];
}

return [{
  json: {
    ...$json,
    message: transcript,
    transcript,
    transcriptionModel: 'whisper-1'
  }
}];

let source = {};
try { source = $('Validate Rabbit token').first().json || {}; } catch (error) {}

function extensionFor(mimeType) {
  const clean = String(mimeType || '').split(';')[0].trim().toLowerCase();
  if (clean.includes('png')) return 'png';
  if (clean.includes('gif')) return 'gif';
  if (clean.includes('webp')) return 'webp';
  return 'jpg';
}

const rawBase64 = String(source.imageBase64 || '').replace(/^data:.*?;base64,/, '').trim();
const notionPageId = String($json.id || $json.pageId || '').trim();
const mimeType = String(source.imageMimeType || 'image/jpeg').split(';')[0].trim() || 'image/jpeg';
const extension = extensionFor(mimeType);
const safeName = String(source.imageName || `rabbit-r1-photo.${extension}`).replace(/[^a-z0-9._-]/gi, '_');
const fileName = safeName.includes('.') ? safeName : `rabbit-r1-photo.${extension}`;

if (!rawBase64 || !notionPageId) {
  return [{
    json: {
      ...$json,
      notionPageId,
      hasPhoto: false,
      photoUploadError: rawBase64 ? 'missing_notion_page_id' : ''
    }
  }];
}

return [{
  json: {
    ...$json,
    notionPageId,
    hasPhoto: true,
    imageMimeType: mimeType,
    imageName: fileName
  },
  binary: {
    photo: {
      data: rawBase64,
      mimeType,
      fileName,
      fileExtension: extension
    }
  }
}];

let prepared = { json: {}, binary: {} };
try { prepared = $('Prepare Notion photo binary').first() || prepared; } catch (error) {}

return [{
  json: {
    ...prepared.json,
    fileUploadId: $json.id || '',
    uploadUrl: $json.upload_url || '',
    fileUploadStatus: $json.status || '',
    fileUploadError: $json.error?.message || ''
  },
  binary: prepared.binary || {}
}];
